import styled from '@emotion/styled'
import { VerticalCenterContainer } from '@kyokuya-demo/component/container'
import type { ISudokuData } from '@kyokuya/react-game-sudoku'
import {
  SudokuActionType,
  SudokuBoard,
  SudokuContextProvider,
  SudokuGame,
  useSudokuContext,
} from '@kyokuya/react-game-sudoku'
import Slider from '@mui/material/Slider'
import React from 'react'

const SUDOKU_SIZE_SQRT = 3
const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

const SudokuGameDemoContainer = styled(VerticalCenterContainer)`
  margin: 2rem 0;
  background: #f3f3f3;

  @media screen and (max-width: 767px) {
    margin-left: -1rem;
    width: calc(100vw - 2px);
    .game-sudoku {
      width: 100%;
    }
  }
`

export const SudokuGameDemo: React.FC = () => (
  <SudokuGameDemoContainer>
    <SudokuGame storageKey="@post/game/sudoku/context0" />
  </SudokuGameDemoContainer>
)

export const SudokuBoard1: React.FC = () => {
  const customizedData = React.useMemo<Partial<ISudokuData>>(
    () => ({ activatedCell: { r: SUDOKU_SIZE >> 1, c: SUDOKU_SIZE >> 1 } }),
    [],
  )

  const Inner: React.FC = () => {
    const [solution] = useSudokuContext(store => [store.state.solution])
    return <SudokuBoard attempt={solution} hintCell={null} />
  }

  return (
    <VerticalCenterContainer>
      <SudokuContextProvider storageKey="@post/game/sudoku/context1" initialData={customizedData}>
        <Inner />
      </SudokuContextProvider>
    </VerticalCenterContainer>
  )
}

const SudokuBoard2Container = styled(VerticalCenterContainer)`
  margin: 2rem 0;
`
export const SudokuBoard2: React.FC = () => {
  const customizedData = React.useMemo<Partial<ISudokuData>>(
    () => ({ activatedCell: { r: SUDOKU_SIZE >> 1, c: SUDOKU_SIZE >> 1 } }),
    [],
  )

  const Inner: React.FC = () => {
    const [dispatch, difficulty, attempt] = useSudokuContext(({ state, dispatch }) => [
      dispatch,
      state.difficulty,
      state.attempt,
    ])
    return (
      <React.Fragment>
        <Slider
          value={difficulty}
          step={1}
          min={0}
          max={100}
          valueLabelDisplay="on"
          aria-labelledby="sudoku-difficulty"
          onChange={(e, v) =>
            dispatch({
              type: SudokuActionType.RESET,
              payload: { difficulty: v as number },
            })
          }
          style={{ maxWidth: 400, margin: '8px 0' }}
        />
        <SudokuBoard attempt={attempt} hintCell={null} />
      </React.Fragment>
    )
  }

  return (
    <SudokuBoard2Container>
      <SudokuContextProvider storageKey="@post/game/sudoku/context2" initialData={customizedData}>
        <Inner />
      </SudokuContextProvider>
    </SudokuBoard2Container>
  )
}
